class Solution:
    def waysToPartition(self, nums, k):
        n = len(nums)
        def count(arr):
            total = sum(arr)
            c = 0
            s = 0
            for p in range(1, n):
                s += arr[p - 1]
                if 2 * s == total:
                    c += 1
            return c
        best = count(nums)
        for i in range(n):
            arr = nums[:i] + [k] + nums[i + 1:]
            best = max(best, count(arr))
        return best

