var waysToPartition = function(nums, k) {
    const n = nums.length;
    let total = 0;
    for (const v of nums) total += v;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + nums[i];
    const rightCount = new Map();
    for (let p = 1; p < n; p++) {
        const val = 2 * prefix[p] - total;
        rightCount.set(val, (rightCount.get(val) || 0) + 1);
    }
    let base = rightCount.get(0) || 0;
    const leftCount = new Map();
    let ans = base;
    for (let i = 0; i < n; i++) {
        const delta = k - nums[i];
        const cur = (leftCount.get(delta) || 0) + (rightCount.get(-delta) || 0);
        if (cur > ans) ans = cur;
        const p = i + 1;
        if (p <= n - 1) {
            const val = 2 * prefix[p] - total;
            rightCount.set(val, (rightCount.get(val) || 0) - 1);
            leftCount.set(val, (leftCount.get(val) || 0) + 1);
        }
    }
    return ans;
};
